queries.item:
REPLACE INTO ?:privileges (privilege, is_default, section_id, group_id, is_view)
VALUES ('abt__ut2.settings.view', 'Y', 'ab__addons', 'abt__unitheme2', 'Y')
,('abt__ut2.settings.manage', 'Y', 'ab__addons', 'abt__unitheme2', 'N');

CREATE TABLE IF NOT EXISTS ?:abt__ut2_microdata (
id mediumint(8) unsigned NOT NULL AUTO_INCREMENT,
company_id int(11) unsigned NOT NULL DEFAULT 0,
field varchar(255) NOT NULL DEFAULT '',
PRIMARY KEY (id)
) DEFAULT CHARSET=utf8;

CREATE TABLE IF NOT EXISTS ?:abt__ut2_microdata_description (
id mediumint(8) unsigned NOT NULL,
value varchar(255) NOT NULL DEFAULT '',
lang_code char(2) NOT NULL DEFAULT '',
PRIMARY KEY (id, lang_code)
) DEFAULT CHARSET=utf8;

CREATE TABLE IF NOT EXISTS ?:abt__ut2_checkout_cities (
city_id INT NOT NULL,
country_code VARCHAR(2) NOT NULL,
state_code VARCHAR(32) NOT NULL,
PRIMARY KEY (city_id)
) DEFAULT CHARSET=utf8;

CREATE TABLE IF NOT EXISTS ?:abt__ut2_banner_groups (
banner_group_id INT NOT NULL auto_increment,
PRIMARY KEY (banner_group_id)
) DEFAULT CHARSET=utf8;

CREATE TABLE IF NOT EXISTS ?:abt__ut2_banner_group_descriptions (
banner_group_id INT NOT NULL ,
group_name VARCHAR(255) NOT NULL,
lang_code CHAR(2) NOT NULL,
PRIMARY KEY (banner_group_id,lang_code)
) DEFAULT CHARSET=utf8;
